const items = $input.all();
if (!items.length) {
  return [{ json: {
    status: 'OK',
    count: 0,
    email_subject: null,
    email_body: null,
    summary: 'Alle DB-Konsistenzpruefungen bestanden.'
  }}];
}
const grouped = {};
for (const { json: row } of items) {
  if (!grouped[row.check_type]) grouped[row.check_type] = [];
  grouped[row.check_type].push(row.message);
}
const lines = Object.entries(grouped).map(([type, msgs]) =>
  '<h3>' + type + '</h3><ul>' + msgs.map(m => '<li>' + m + '</li>').join('') + '</ul>'
).join('');
const count = items.length;
const ts = new Date().toISOString();
return [{ json: {
  status: 'FEHLER',
  count,
  grouped,
  email_subject: '[DB-Check] ' + count + ' Konsistenzproblem' + (count !== 1 ? 'e' : '') + ' gefunden',
  email_body: '<h2>DB-Konsistenzpruefung: ' + count + ' Problem' + (count !== 1 ? 'e' : '') + '</h2>' +
    lines + '<p><small>WF-Val Check: ' + ts + '</small></p>'
}}];

